// Client Script for Sales Order DocType
(function() {

    // Helper function to handle focus
    const set_focus_on_item_code = (frm, cdt, cdn) => {
        const timeout_duration = 200;
        setTimeout(() => {
            try {
                const target_field = frm.get_field('items', cdn, 'custom_height');
                
                // 1. Try finding the field wrapper normally
                if (!target_field || !target_field.$wrapper || target_field.df.hidden || target_field.df.read_only || target_field.df.disabled) {
                    const $row_element_fallback = frm.$wrapper.find(`.grid-row[data-name="${cdn}"]`);
                    if ($row_element_fallback.length > 0) {
                        const $input_element_fallback = $row_element_fallback.find('input[data-fieldname="custom_height"]:visible').first();
                        if ($input_element_fallback.length > 0) {
                            $input_element_fallback[0].focus();
                            return;
                        }
                    }
                    return;
                }

                // 2. Try finding input inside the wrapper
                let $input_element = null;
                if (target_field.$wrapper) {
                    $input_element = target_field.$wrapper.find('input[data-fieldname="custom_height"]:visible').first();
                    if (!$input_element || !$input_element.length) {
                        $input_element = target_field.$wrapper.find(':input:visible').first();
                    }
                }

                if ($input_element && $input_element.length > 0) {
                    $input_element[0].focus();
                } else if (target_field.set_focus) {
                    target_field.set_focus();
                } else {
                    target_field.$input && target_field.$input.focus();
                }
            } catch (e) {
                console.error("Focus error", e);
            }
        }, timeout_duration);
    };

    // Main Trigger
    frappe.ui.form.on('Sales Order Item', {
        item_code: function(frm, cdt, cdn) {
            const row = locals[cdt][cdn];

            const SPECIFIC_ITEM_CODES = [
                'Full Round Mould', 'Dhar Mould', 'Half Round Mould', 'Tiles Job Work'
            ];

            const CHECKBOX_FIELDNAMES = {
                'right': 'custom_right',
                'left': 'custom_left',
                'top': 'custom_top',
                'bottom': 'custom_bottom'
            };

            const CUSTOM_DIMENSION_FIELDNAMES = {
                'width': 'custom_width',
                'height': 'custom_height'
            };

            // Check if item matches criteria
            if (SPECIFIC_ITEM_CODES.includes(row.item_code) ||
                (row.item_code && typeof row.item_code === 'string' && row.item_code.includes('MouldG'))) {
                
                // Fetch dimensions from previous row
                let fetched_width = 0;
                let fetched_height = 0;
                const current_row_index = frm.doc.items.findIndex(item => item.name === cdn);

                if (current_row_index > 0) {
                    const previous_row = frm.doc.items[current_row_index - 1];
                    fetched_width = previous_row[CUSTOM_DIMENSION_FIELDNAMES.width] || 0;
                    fetched_height = previous_row[CUSTOM_DIMENSION_FIELDNAMES.height] || 0;
                }

                // ---------------------------------------------------------
                // 1. DEFINE DIALOG (Logic Moved Inside)
                // ---------------------------------------------------------
                
                // We declare dialog variable first so we can use it inside the 'onchange' functions
                let dialog; 

                dialog = new frappe.ui.Dialog({
                    title: 'Item Custom Dimensions',
                    fields: [
                        { fieldname: 'section_main', fieldtype: 'Section Break' },
                        { fieldname: 'col_left', fieldtype: 'Column Break' },
                        
                        // Control Checkboxes with Logic Attached
                        { 
                            fieldname: 'top_bottom', 
                            label: 'Top & Bottom', 
                            fieldtype: 'Check',
                            onchange: function() {
                                if(dialog) {
                                    let val = dialog.get_value('top_bottom');
                                    dialog.set_value('top', val);
                                    dialog.set_value('bottom', val);
                                }
                            }
                        },
                        { 
                            fieldname: 'select_all', 
                            label: 'Select All', 
                            fieldtype: 'Check',
                            onchange: function() {
                                if(dialog) {
                                    let val = dialog.get_value('select_all');
                                    // Update visual fields
                                    dialog.set_value('left', val);
                                    dialog.set_value('right', val);
                                    
                                    // Update the other control field (which will trigger its own logic to update top/bottom)
                                    dialog.set_value('top_bottom', val);
                                }
                            }
                        },

                        { fieldname: 'col_right', fieldtype: 'Column Break' },
                        
                        // Data Checkboxes
                        { fieldname: 'right', label: 'Right', fieldtype: 'Check', default: row[CHECKBOX_FIELDNAMES.right] || 0 },
                        { fieldname: 'left', label: 'Left', fieldtype: 'Check', default: row[CHECKBOX_FIELDNAMES.left] || 0 },
                        { fieldname: 'top', label: 'Top', fieldtype: 'Check', default: row[CHECKBOX_FIELDNAMES.top] || 0 },
                        { fieldname: 'bottom', label: 'Bottom', fieldtype: 'Check', default: row[CHECKBOX_FIELDNAMES.bottom] || 0 },

                        { fieldname: 'section_dimensions', fieldtype: 'Section Break' },
                        {
                            fieldname: 'info_width',
                            label: 'Fetched Width',
                            fieldtype: 'Data',
                            read_only: 1,
                            default: fetched_width,
                            description: `Width fetched from previous item: ${fetched_width}`
                        },
                        {
                            fieldname: 'info_height',
                            label: 'Fetched Height',
                            fieldtype: 'Data',
                            read_only: 1,
                            default: fetched_height,
                            description: `Height fetched from previous item: ${fetched_height}`
                        }
                    ],
                    primary_action_label: 'Apply',
                    primary_action: function(values) {
                        // Update Row Values
                        frappe.model.set_value(cdt, cdn, CHECKBOX_FIELDNAMES.right, values.right);
                        frappe.model.set_value(cdt, cdn, CHECKBOX_FIELDNAMES.left, values.left);
                        frappe.model.set_value(cdt, cdn, CHECKBOX_FIELDNAMES.top, values.top);
                        frappe.model.set_value(cdt, cdn, CHECKBOX_FIELDNAMES.bottom, values.bottom);

                        frappe.model.set_value(cdt, cdn, CUSTOM_DIMENSION_FIELDNAMES.width, values.info_width);
                        frappe.model.set_value(cdt, cdn, CUSTOM_DIMENSION_FIELDNAMES.height, values.info_height);

                        dialog.hide();
                        set_focus_on_item_code(frm, cdt, cdn);
                    }
                });

                // ---------------------------------------------------------
                // 2. SHOW DIALOG
                // ---------------------------------------------------------
                dialog.show();

            } else {
                // Fallback if item is not special
                set_focus_on_item_code(frm, cdt, cdn);
            }
        }
    });
})();

// Wrap the entire script in an IIFE to create a private scope
(function() {

    // --- Helper for getting positive float values ---
    function getPositiveFloat(value) {
        return Math.max(0, parseFloat(value) || 0);
    }

    /**
     * Calculates the segment value for Height, and also for the special width rule.
     * Rule: Rounds up to the next multiple of 6. If already a multiple of 6, adds 6.
     * @param {number} value The input dimension.
     * @returns {number} The calculated segment value.
     */
    function calculateSegments_Special(value) {
        const val = getPositiveFloat(value);
        if (val === 0) return 0;
        return (val % 6 === 0) ? (val + 6) : (Math.ceil(val / 6) * 6);
    }

    // --- NEW ---
    /**
     * Calculates width segments using the special rule for when HEIGHT is LESS THAN 24.
     * Rule: if width is > 15 and < 18, segment is 18.
     * @param {number} value The input width.
     * @returns {number} The calculated segment value.
     */
    function calculateWidthSegments_HeightRule(value) {
        const val = getPositiveFloat(value);
        if (val === 0) return 0;

        if (val > 1 && val < 6) return 6;
        if (val >= 6 && val < 12) return 12;
        if (val >= 12 && val < 15) return 30;
        if (val === 15) return 18;
        if (val > 15 && val < 18) return 18; // The special rule as requested
        if (val >= 18) {
            return calculateSegments_Special(val);
        }
        return 0; // Default case
    }


    /**
     * Calculates the segment value for Width using the ORIGINAL/STANDARD logic.
     * This is used for items that are NOT Rajsthan or Kaddpa AND when height is >= 24.
     * @param {number} value The input width.
     * @returns {number} The calculated segment value.
     */
    function calculateWidthSegments_Standard(value) {
        const val = getPositiveFloat(value);
        if (val === 0) return 0;

        if (val > 1 && val < 6) return 6;
        if (val >= 6 && val < 12) return 12;
        if (val >= 12 && val < 15) return 30;
        if (val === 15) return 18;
        if (val > 15 && val < 18) return 24; // Original logic
        if (val >= 18) {
            return calculateSegments_Special(val);
        }
        return 0; // Default case
    }


    /**
     * Opens a dialog to build a custom item code, then finds the item and sets it in the grid.
     */
    function open_custom_item_details_dialog(frm, cdt, cdn, row) {
        // --- Determine initial values from the grid row ---
        let initial_polish_type = '';
        if (row.custom_fine_polish) initial_polish_type = 'Fine';
        else if (row.custom_rough_polish) initial_polish_type = 'Rough';
        else if (row.custom_polish_type) initial_polish_type = 'Polish';
        else if (row.custom_dp) initial_polish_type = 'DP';
        else if (row.custom_uncut) initial_polish_type = 'Uncut';
        else if (row.custom_ledhar) initial_polish_type = 'Ledhar';
        else if (row.custom_river) initial_polish_type = 'River';

        let initial_is_rough = row.custom_is_rough || 0;
        let initial_is_rajsthan = row.custom_is_rajsthan || 0;
        let initial_is_gadela = row.custom_is_gadela || 0;
        let initial_is_patala = row.custom_is_patala || 0;
        let initial_is_jada = row.custom_is_jada || 0;

        var dialog;

        const set_focus_on_custom_height = (frm, cdt, cdn) => {
            setTimeout(() => {
                try {
                    const field = frm.get_field('items', cdn, 'custom_height');
                    if (field && field.set_focus) field.set_focus();
                } catch (e) { /* Suppress error if field not found */ }
            }, 200);
        };

        // --- MODIFIED: Centralized function to decide which width calculation to use and apply it ---
        const triggerWidthCalculation = () => {
            if (dialog && !dialog.get_value('manual_segments_toggle')) {
                const template = dialog.get_value('item_template_filter');
                const is_rajsthan = dialog.get_value('custom_is_rajsthan');
                const width_val = dialog.get_value('custom_width');
                const height_val = dialog.get_value('custom_height');

                let calculated_width;
                if (template === 'KADDPA' || is_rajsthan) {
                    // Kaddpa and Rajsthan have their own special logic that takes precedence
                    calculated_width = calculateSegments_Special(width_val);
                } else if (getPositiveFloat(height_val) < 24) {
                    // If height is less than 24, use the new special rule
                    calculated_width = calculateWidthSegments_HeightRule(width_val);
                } else {
                    // Otherwise (height >= 24), use the original standard logic
                    calculated_width = calculateWidthSegments_Standard(width_val);
                }
                dialog.set_value('custom_cut_from_width', calculated_width);
            }
        };

        const template_options = [
            { label: 'Kota', value: 'KOTA' },
            { label: 'Kaddpa', value: 'KADDPA' }
        ];

        const dialog_fields = [
            { label: 'Item Name', fieldname: 'item_template_filter', fieldtype: 'Select', options: template_options, default: 'KOTA', reqd: 1,
                onchange: triggerWidthCalculation
            },
            { fieldname: 'section_dimensions', fieldtype: 'Section Break', label: 'Item Dimensions' },
            { label: 'Height', fieldname: 'custom_height', fieldtype: 'Float', default: row.custom_height, reqd: 1,
                // --- MODIFIED: onchange now triggers width calculation ---
                onchange: function() {
                    if (!dialog.get_value('manual_segments_toggle')) {
                        dialog.set_value('custom_cut_from_height', calculateSegments_Special(dialog.get_value('custom_height')));
                    }
                    // Re-evaluate the width logic whenever the height changes
                    triggerWidthCalculation();
                }
            },
            { label: 'Height Segments', fieldname: 'custom_cut_from_height', fieldtype: 'Float', default: calculateSegments_Special(row.custom_height), read_only: 1, reqd: 1 },
            { fieldname: 'col_break_dims', fieldtype: 'Column Break' },
            { label: 'Width', fieldname: 'custom_width', fieldtype: 'Float', default: row.custom_width, reqd: 1,
                onchange: triggerWidthCalculation
            },
            { label: 'Width Segments', fieldname: 'custom_cut_from_width', fieldtype: 'Float', default: 0, read_only: 1, reqd: 1 },
            { fieldname: 'col_break_manual_toggle', fieldtype: 'Column Break' },
            { label: 'Edit Segments Manually', fieldname: 'manual_segments_toggle', fieldtype: 'Check', default: 0,
                onchange: function() {
                    const is_manual = dialog.get_value('manual_segments_toggle');
                    
                    let height_segment_field = dialog.get_field('custom_cut_from_height');
                    let width_segment_field = dialog.get_field('custom_cut_from_width');

                    height_segment_field.df.read_only = !is_manual;
                    width_segment_field.df.read_only = !is_manual;
                    
                    height_segment_field.refresh();
                    width_segment_field.refresh();

                    if (!is_manual) {
                        // Trigger the onchange event which will recalculate both height and width segments
                        dialog.get_field('custom_height').df.onchange();
                    }
                }
            },
            { fieldname: 'section_properties', fieldtype: 'Section Break', label: 'Item Properties' },
            { label: 'Polish/Finish Type', fieldname: 'polish_type', fieldtype: 'Select', options: ['Fine', 'Rough', 'Polish', 'DP', 'Uncut', 'Ledhar', 'River', ''], default: initial_polish_type,
                onchange: function() {
                    if (dialog.get_value('polish_type')) {
                        dialog.set_value('custom_is_rough', 0);
                        dialog.set_value('custom_is_rajsthan', 0);
                        dialog.set_value('custom_is_gadela', 0);
                        dialog.set_value('custom_is_patala', 0);
                        dialog.set_value('custom_is_jada', 0);
                        triggerWidthCalculation();
                    }
                }
            },
            { fieldname: 'col_break_attributes', fieldtype: 'Column Break' },
            { label: 'Rough', fieldname: 'custom_is_rough', fieldtype: 'Check', default: initial_is_rough,
                onchange: function() { if (dialog.get_value('custom_is_rough')) { dialog.set_value('polish_type', ''); } }
            },
            { label: 'Rajsthan', fieldname: 'custom_is_rajsthan', fieldtype: 'Check', default: initial_is_rajsthan,
                onchange: function() {if (dialog.get_value('custom_is_rajsthan')) { dialog.set_value('polish_type', ''); }
                    triggerWidthCalculation();
                }
            },
            { label: 'Gadela', fieldname: 'custom_is_gadela', fieldtype: 'Check', default: initial_is_gadela,
                onchange: function() { if (dialog.get_value('custom_is_gadela')) { dialog.set_value('polish_type', ''); } }
            },
            { label: 'Patala', fieldname: 'custom_is_patala', fieldtype: 'Check', default: initial_is_patala,
                onchange: function() { if (dialog.get_value('custom_is_patala')) { dialog.set_value('custom_is_jada', 0); dialog.set_value('polish_type', ''); } }
            },
            { label: 'Jada', fieldname: 'custom_is_jada', fieldtype: 'Check', default: initial_is_jada,
                onchange: function() { if (dialog.get_value('custom_is_jada')) { dialog.set_value('custom_is_patala', 0); dialog.set_value('polish_type', ''); } }
            },
        ];

        dialog = new frappe.ui.Dialog({
            title: 'Edit Item Details & Select Item',
            fields: dialog_fields,
            primary_action_label: 'Generate & Find Item',
            primary_action(values) {
                const template = values.item_template_filter;
                const actual_height = values.custom_height;
                const actual_width = values.custom_width;
                const cut_height = values.custom_cut_from_height;
                const cut_width = values.custom_cut_from_width;

                if (!template || !actual_height || !actual_width || actual_height <= 0 || actual_width <= 0) {
                    frappe.msgprint(__('Please select a Template and ensure positive Height and Width values are entered.'));
                    return;
                }

                let dimensions_part;
                if (values.custom_is_rajsthan && !values.custom_is_gadela) {
                    dimensions_part = `${actual_height}x${actual_width}`;
                } else {
                    dimensions_part = `${cut_height}x${cut_width}`;
                }

                let target_item_code = `${template} ${dimensions_part}`;

                const polish_suffix_map = { 'Fine': ' FIN', 'Rough': ' RUF', 'Polish': '', 'DP': ' DP', 'Uncut': ' UNC', 'Ledhar': ' LDR', 'River': ' RIV' };
                if (values.polish_type && polish_suffix_map[values.polish_type] !== undefined) {
                    target_item_code += polish_suffix_map[values.polish_type];
                } else {
                    if (values.custom_is_rajsthan) target_item_code += ' RAJ';
                    if (values.custom_is_gadela) target_item_code += ' G';
                    if (values.custom_is_rough) target_item_code += ' RUF';
                    if (values.custom_is_patala) target_item_code += ' P';
                    else if (values.custom_is_jada) target_item_code += ' J';
                }

                frappe.model.set_value(cdt, cdn, {
                    'custom_height': values.custom_height,
                    'custom_width': values.custom_width,
                    'custom_fine_polish': (values.polish_type === 'Fine' ? 1 : 0),
                    'custom_rough_polish': (values.polish_type === 'Rough' ? 1 : 0),
                    'custom_polish_type': (values.polish_type === 'Polish' ? 1 : 0),
                    'custom_dp': (values.polish_type === 'DP' ? 1 : 0),
                    'custom_uncut': (values.polish_type === 'Uncut' ? 1 : 0),
                    'custom_ledhar': (values.polish_type === 'Ledhar' ? 1 : 0),
                    'custom_river': (values.polish_type === 'River' ? 1 : 0),
                    'custom_is_rough': values.custom_is_rough,
                    'custom_is_rajsthan': values.custom_is_rajsthan,
                    'custom_is_gadela': values.custom_is_gadela,
                    'custom_is_patala': values.custom_is_patala,
                    'custom_is_jada': values.custom_is_jada
                });

                frappe.call({
                    method: 'frappe.client.get_list',
                    args: {
                        doctype: 'Item',
                        filters: { 'item_code': target_item_code },
                        fields: ['item_code'],
                        limit_page_length: 1
                    },
                    callback: function(response) {
                        dialog.hide();
                        if (response.message && response.message.length > 0) {
                            frappe.model.set_value(cdt, cdn, 'item_code', response.message[0].item_code);
                        } else {
                            frappe.model.set_value(cdt, cdn, 'item_code', null);
                            frappe.msgprint(__(`Item not found: ${target_item_code}. Please create this item or adjust the inputs.`));
                        }
                        frm.refresh_field('items');
                        set_focus_on_custom_height(frm, cdt, cdn);
                    },
                    error: function(err) {
                        dialog.hide();
                        frappe.msgprint(__(`Error during item lookup: ${err.message || err}`));
                        set_focus_on_custom_height(frm, cdt, cdn);
                    }
                });
            },
            on_close: function() {
                set_focus_on_custom_height(frm, cdt, cdn);
            }
        });
        
        // Trigger the initial calculation when the dialog opens
        triggerWidthCalculation();

        dialog.show();
    }


    // --- Frappe Event Handlers ---
    frappe.ui.form.on('Sales Order Item', {
        custom_select_item: function(frm, cdt, cdn) {
            let row = frappe.get_doc(cdt, cdn);
            open_custom_item_details_dialog(frm, cdt, cdn, row);
        },
    });

})(); // End of IIFE

// --- Debounce Helper Function ---
const debounce = (func, delay) => {
    let timeoutId;
    return (...args) => {
        clearTimeout(timeoutId);
        timeoutId = setTimeout(() => {
            func.apply(this, args);
        }, delay);
    };
};

// --- Math Helpers ---
const getPositiveFloat = (v) => Math.max(0, parseFloat(v) || 0);
const getNextMultipleOf = (val, mul) => (val <= 0) ? 0 : ((val % mul === 0) ? val : Math.ceil(val / mul) * mul);
const getKotaPlus6 = (val) => (val <= 0) ? 0 : ((val % 6 === 0) ? (val + 6) : (Math.ceil(val / 6) * 6));
const getStrictNext6 = (val) => (val <= 0) ? 0 : (Math.floor(val / 6) + 1) * 6;

// --- KOTA Width Logic (Scenario B) ---
const getKotaWidth_Pair = (w) => {
    if (w < 6) return 6;
    if (w < 12) return 12;
    if (w < 15) return 15;
    if (w < 18) return 18;
    return getKotaPlus6(w);
};

const getKotaWidth_Single = (w) => {
    if (w < 6) return 6;
    if (w < 12) return 12;
    if (w < 18) return 18;
    return getKotaPlus6(w);
};

const getKotaWidth_Small = (w) => {
    if (w <= 5) return 6;
    if (w <= 11) return 12;
    if (w <= 14) return 15;
    if (w < 18) return 18;
    return getKotaPlus6(w);
};

// --- Main Calculation Function ---
function calculateSqft(frm, cdt, cdn) {
    const row = locals[cdt][cdn];
    if (!row || !row.item_code) return;

    const itemCode = String(row.item_code).toLowerCase();
    const h = getPositiveFloat(row.custom_height);
    const w = getPositiveFloat(row.custom_width);
    const qtyInput = getPositiveFloat(row.custom_quantity);
    
    // Exclusion Keywords
    const strictExclusions = ['mould', 'mouldg', 'hole', 'farma', 'tiles'];
    if (strictExclusions.some(k => itemCode.includes(k))) return;

    let cutH = 0, cutW = 0, finalQtySqft = 0;

    // 1. PATI Logic
    if (itemCode.includes('pati')) {
        cutH = getNextMultipleOf(h, 6);
        cutW = (w < 12) ? 12 : getNextMultipleOf(w, 3);
        finalQtySqft = ((cutH * cutW) / 144) * qtyInput;
    } 
    // 2. RAJ KOTA Logic
    else if (itemCode.includes('raj') && itemCode.includes('kota')) {
        cutH = getKotaPlus6(h);
        cutW = getKotaPlus6(w);
        finalQtySqft = ((cutH * cutW) / 144) * qtyInput;
    } 
    // 3. KOTA ONLY Logic (Scenario B)
    else if (itemCode.startsWith('kota')) {
        cutH = (h > 0) ? getStrictNext6(h) : 0;

        if (h < 24) {
            cutW = getKotaWidth_Small(w);
            finalQtySqft = ((cutH * cutW) / 144) * qtyInput;
        } else {
            let evenQtyCount = Math.floor(qtyInput / 2) * 2;
            let oddQtyCount = qtyInput % 2;
            
            let sqftEven = 0, sqftOdd = 0;
            let wPair = getKotaWidth_Pair(w);
            let wSingle = getKotaWidth_Single(w);

            if (evenQtyCount > 0) sqftEven = ((cutH * wPair) / 144) * evenQtyCount;
            if (oddQtyCount > 0) sqftOdd = ((cutH * wSingle) / 144) * oddQtyCount;
            
            finalQtySqft = sqftEven + sqftOdd;
            // Display width based on majority or single
            cutW = (qtyInput === 1) ? wSingle : wPair; 
        }
    } 
    // 4. KADDPA Logic
    else if (itemCode.includes('kaddpa')) {
        cutH = getNextMultipleOf(h, 6);
        cutW = getNextMultipleOf(w, 6);
        finalQtySqft = ((cutH * cutW) / 144) * qtyInput;
    } 
    // 5. Default GRANITE Logic
    else {
        cutH = getNextMultipleOf(h, 3);
        cutW = getNextMultipleOf(w, 3);
        finalQtySqft = ((cutH * cutW) / 144) * qtyInput;
    }

    // Apply Changes
    let changes = {};
    const newSqft = parseFloat(finalQtySqft.toFixed(4));

    if (getPositiveFloat(row.cut_from_height) !== cutH) changes.cut_from_height = cutH;
    if (getPositiveFloat(row.cut_from_width) !== cutW) changes.cut_from_width = cutW;
    if (getPositiveFloat(row.qty) !== newSqft) changes.qty = newSqft;

    if (Object.keys(changes).length > 0) {
        frappe.model.set_value(cdt, cdn, changes);
    }
}

// --- Initialize Triggers ---
const debouncedCalculateSqft = debounce(calculateSqft, 300);

frappe.ui.form.on('Sales Order Item', {
    item_code: (frm, cdt, cdn) => calculateSqft(frm, cdt, cdn), // Immediate for item change
    custom_height: (frm, cdt, cdn) => debouncedCalculateSqft(frm, cdt, cdn),
    custom_width: (frm, cdt, cdn) => debouncedCalculateSqft(frm, cdt, cdn),
    custom_quantity: (frm, cdt, cdn) => debouncedCalculateSqft(frm, cdt, cdn)
});

// Function to round up to the nearest multiple of 'factor'
function roundUpToNearestMultiple(value, factor) {
    if (value === 0) return 0;
    return Math.ceil(value / factor) * factor;
}

frappe.ui.form.on('Sales Order Item', {
    custom_quantity: function(frm, cdt, cdn) {
        var row = frappe.get_doc(cdt, cdn);
        
        if (!row.item_code) return;

        let item_code_upper = row.item_code.toUpperCase();
        let factor = 0;

        // Determine rounding factor based on Item Code
        if (item_code_upper.includes('MOULDG') || item_code_upper.includes('TILES')) {
            factor = 3;
        } else if (item_code_upper.includes('MOULD')) {
            factor = 6;
        }

        // If a factor was assigned, perform the calculation
        if (factor > 0) {
            let running_foot = 0;
            let original_width = parseFloat(row.custom_width) || 0;
            let original_height = parseFloat(row.custom_height) || 0;
            let custom_qty = parseFloat(row.custom_quantity) || 0;

            // Calculate rounded dimensions in feet (dividing by 12)
            let calc_width = roundUpToNearestMultiple(original_width, factor) / 12;
            let calc_height = roundUpToNearestMultiple(original_height, factor) / 12;

            // Calculate Running Feet based on selected sides
            if (row.custom_right && row.custom_left) {
                running_foot += (2 * calc_width);
            } else if (row.custom_right || row.custom_left) {
                running_foot += calc_width;
            }

            if (row.custom_top && row.custom_bottom) {
                running_foot += (2 * calc_height);
            } else if (row.custom_top || row.custom_bottom) {
                running_foot += calc_height;
            }

            // Set final Qty: (Running Feet per unit) * (Number of units)
            let total_qty = running_foot * custom_qty;
            frappe.model.set_value(cdt, cdn, 'qty', total_qty);
            
            // Log for debugging
            console.log(`Item: ${row.item_code} | Factor: ${factor} | Total Qty: ${total_qty}`);
            
            frm.refresh_field('items');
        }
    }
});

frappe.ui.form.on('WhatsApp Settings', {
    refresh: function(frm) {
        // Create the blue button at the top
        frm.add_custom_button(__('Check Connection & Get QR'), function() {
            let target_url = frm.doc.waha_api_url || frm.doc.waha_base_url;
            
            if (!target_url || !frm.doc.default_session) {
                frappe.msgprint("Please enter the WAHA URL and Session Name first.");
                return;
            }

            frappe.show_alert("Checking WAHA Server...");

            // Call our Python Server Script
            frappe.call({
                method: 'waha_check_status_and_connect',
                args: {
                    url: target_url,
                    session: frm.doc.default_session,
                    docname: frm.doc.name
                },
                callback: function(r) {
                    if (r.message && r.message.status) {
                        let status = r.message.status;
                        
                        // Update the text field
                        frm.set_value('connection_status', status);

                        // If QR is ready, show the image securely fetched by Python
                        if (status === "SCAN_QR_CODE") {
                            let img_src = r.message.qr_base64 || "";
                            let html = `
                                <div style="text-align: center; padding: 20px; background: #f8f9fa; border-radius: 8px;">
                                    <h4>Scan this QR Code with WhatsApp</h4>
                                    <img src="${img_src}" alt="QR Code" style="max-width: 300px; border: 1px solid #ddd; border-radius: 8px;" />
                                    <p class="text-muted mt-2">If QR is expired, click 'Check Connection' again to refresh.</p>
                                </div>
                            `;
                            frm.set_df_property('qr_code_view', 'options', html);
                        } 
                        // If it is working, show the green success message!
                        else if (status === "WORKING") {
                            frm.set_df_property('qr_code_view', 'options', 
                                '<div style="color: #155724; background-color: #d4edda; border-color: #c3e6cb; font-weight: bold; text-align: center; padding: 20px; border-radius: 8px;">✅ WhatsApp is Connected and Working!</div>'
                            );
                        } 
                        // Show current status/loading or debug trail if there is an error
                        else {
                            let error_details = r.message.details ? `<br><small style="color:#666; margin-top:10px; display:block; text-align:left;"><b>Debug Log:</b><br>${r.message.details}</small>` : '';
                            frm.set_df_property('qr_code_view', 'options', 
                                `<div style="text-align: center; padding: 20px; background: #fff3cd; border-radius: 8px;">Current Status: <b>${status}</b>${error_details}</div>`
                            );
                        }
                    }
                }
            });
        }).addClass('btn-primary'); // Makes the button blue
    }
});
